// --- Input Validation ---

function validateAuthorizationCode(code) {
  if (!code || typeof code !== 'string') {
    throw new Error('Invalid authorization code');
  }
  // Authorization codes should be alphanumeric with limited special chars
  const codePattern = /^[a-zA-Z0-9\-._~]+$/;
  if (!codePattern.test(code) || code.length > 2048) {
    throw new Error('Authorization code contains invalid characters or is too long');
  }
  return code;
}

function validateState(receivedState, expectedState) {
  if (!receivedState || !expectedState) {
    throw new Error('Missing state parameter');
  }
  if (receivedState !== expectedState) {
    throw new Error('State mismatch - possible CSRF attack');
  }
  return true;
}

function validateTokenResponse(response) {
  if (!response || typeof response !== 'object') {
    throw new Error('Invalid token response');
  }
  if (!response.access_token || typeof response.access_token !== 'string') {
    throw new Error('Missing or invalid access token in response');
  }
  if (!response.token_type || response.token_type.toLowerCase() !== 'bearer') {
    throw new Error('Invalid token type');
  }
  if (response.expires_in && (typeof response.expires_in !== 'number' || response.expires_in <= 0)) {
    throw new Error('Invalid token expiry');
  }
  return response;
}

function validateIdToken(idToken, nonce) {
  if (!idToken) return null;

  try {
    const parts = idToken.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid ID token format');
    }

    const payload = JSON.parse(atob(parts[1].replace(/-/g, '+').replace(/_/g, '/')));

    // Validate nonce to prevent replay attacks
    if (nonce && payload.nonce !== nonce) {
      throw new Error('ID token nonce mismatch');
    }

    // Validate expiry
    if (payload.exp && Date.now() / 1000 > payload.exp) {
      throw new Error('ID token has expired');
    }

    // Validate issuer matches expected
    if (payload.iss) {
      const expectedIssuer = new URL(OAUTH_CONFIG.authorizationEndpoint).origin;
      if (!payload.iss.startsWith(expectedIssuer)) {
        throw new Error('ID token issuer mismatch');
      }
    }

    // Validate audience
    if (payload.aud && payload.aud !== OAUTH_CONFIG.clientId) {
      if (Array.isArray(payload.aud) && !payload.aud.includes(OAUTH_CONFIG.clientId)) {
        throw new Error('ID token audience mismatch');
      }
    }

    return payload;
  } catch (error) {
    if (error.message.includes('ID token')) {
      throw error;
    }
    throw new Error('Failed to parse ID token');
  }
}

