function OAuthCallback() {
  const { handleCallback, isLoading, error } = useAuth();
  const [processed, setProcessed] = useState(false);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    if (processed) return;

    const processCallback = async () => {
      const urlParams = new URLSearchParams(window.location.search);
      const code = urlParams.get('code');
      const state = urlParams.get('state');
      const errorParam = urlParams.get('error');
      const errorDescription = urlParams.get('error_description');

      // Clean URL to remove sensitive parameters
      window.history.replaceState({}, document.title, window.location.pathname);

      if (errorParam) {
        setProcessed(true);
        setSuccess(false);
        return;
      }

      if (!code || !state) {
        setProcessed(true);
        setSuccess(false);
        return;
      }

      const result = await handleCallback(code, state);
      setProcessed(true);
      setSuccess(result);

      if (result) {
        // Redirect to home after successful authentication
        window.location.href = '/';
      }
    };

    processCallback();
  }, [handleCallback, processed]);

  if (isLoading || !processed) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement('div', { style: styles.spinner }),
      React.createElement('p', { style: styles.text }, 'Processing authentication...')
    );
  }

  if (error || !success) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement('div', { style: styles.errorCard },
        React.createElement('h2', { style: styles.errorTitle }, 'Authentication Failed'),
        React.createElement('p', { style: styles.errorText }, error || 'An unknown error occurred'),
        React.createElement(
          'button',
          {
            style: styles.button,
            onClick: () => { window.location.href = '/'; },
          },
          'Return to Home'
        )
      )
    );
  }

  return React.createElement(
    'div',
    { style: styles.container },
    React.createElement('p', { style: styles.text }, 'Authentication successful! Redirecting...')
  );
}

